#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdlib.h>
#include <cuda.h>
#include <cuda_runtime.h>

#define OPEN
#define NUM_THREAD 512

FILE *fp;

struct Node
{
    int starting;
    int no_of_edges;
};

__global__ void Kernel(Node* g_graph_nodes, int* g_graph_edges, bool* g_graph_mask, bool* g_updating_graph_mask, bool* g_graph_visited, int* g_cost, int no_of_nodes)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if(tid < no_of_nodes && g_graph_mask[tid])
    {
        g_graph_mask[tid] = false;
        for(int i = g_graph_nodes[tid].starting; i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting); i++)
        {
            int id = g_graph_edges[i];
            if(!g_graph_visited[id])
            {
                g_cost[id] = g_cost[tid] + 1;
                g_updating_graph_mask[id] = true;
            }
        }
    }
}

__global__ void Kernel2(bool* g_graph_mask, bool* g_updating_graph_mask, bool* g_graph_visited, bool* g_over, int no_of_nodes)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if(tid < no_of_nodes && g_updating_graph_mask[tid])
    {
        g_graph_mask[tid] = true;
        g_graph_visited[tid] = true;
        *g_over = true;
        g_updating_graph_mask[tid] = false;
    }
}

void Usage(int argc, char**argv){
    fprintf(stderr,"Usage: %s <num_threads> <input_file>\n", argv[0]);
}

void BFSGraph(int argc, char** argv)
{
    int no_of_nodes = 0;
    int edge_list_size = 0;
    char *input_f;
    int num_omp_threads;

    if(argc != 3){
        Usage(argc, argv);
        exit(0);
    }

    num_omp_threads = atoi(argv[1]);
    input_f = argv[2];

    printf("Reading File\n");
    fp = fopen(input_f, "r");
    if(!fp)
    {
        printf("Error Reading graph file\n");
        return;
    }

    int source = 0;
    fscanf(fp, "%d", &no_of_nodes);

    Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
    bool *h_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
    bool *h_updating_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
    bool *h_graph_visited = (bool*) malloc(sizeof(bool)*no_of_nodes);

    int start, edgeno;
    for(unsigned int i = 0; i < (unsigned int)no_of_nodes; i++)
    {
        fscanf(fp, "%d %d", &start, &edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = false;
        h_updating_graph_mask[i] = false;
        h_graph_visited[i] = false;
    }

    fscanf(fp, "%d", &source);

    h_graph_mask[source] = true;
    h_graph_visited[source] = true;

    fscanf(fp, "%d", &edge_list_size);

    int id, cost;
    int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
    for(int i = 0; i < edge_list_size; i++)
    {
        fscanf(fp, "%d", &id);
        fscanf(fp, "%d", &cost);
        h_graph_edges[i] = id;
    }

    if(fp)
        fclose(fp);

    int* h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
    for(int i = 0; i < no_of_nodes; i++)
        h_cost[i] = -1;
    h_cost[source] = 0;

    printf("Start traversing the tree\n");

    Node* d_graph_nodes;
    bool* d_graph_mask;
    bool* d_updating_graph_mask;
    bool* d_graph_visited;
    int* d_graph_edges;
    int* d_cost;
    bool* d_over;

    cudaMalloc((void**)&d_graph_nodes, sizeof(Node)*no_of_nodes);
    cudaMalloc((void**)&d_graph_mask, sizeof(bool)*no_of_nodes);
    cudaMalloc((void**)&d_updating_graph_mask, sizeof(bool)*no_of_nodes);
    cudaMalloc((void**)&d_graph_visited, sizeof(bool)*no_of_nodes);
    cudaMalloc((void**)&d_graph_edges, sizeof(int)*edge_list_size);
    cudaMalloc((void**)&d_cost, sizeof(int)*no_of_nodes);
    cudaMalloc((void**)&d_over, sizeof(bool));

    cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node)*no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(bool)*no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool)*no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool)*no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int)*edge_list_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_cost, h_cost, sizeof(int)*no_of_nodes, cudaMemcpyHostToDevice);

    int num_of_blocks = 1;
    int num_of_threads_per_block = no_of_nodes;

    if(no_of_nodes > NUM_THREAD)
    {
        num_of_blocks = (int)ceil((double)no_of_nodes / (double)NUM_THREAD);
        num_of_threads_per_block = NUM_THREAD;
    }

    dim3 grid(num_of_blocks, 1, 1);
    dim3 threads(num_of_threads_per_block, 1, 1);

    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);
    cudaEventRecord(start_event, 0);

    int k = 0;
    bool stop;
    do
    {
        stop = false;
        cudaMemcpy(d_over, &stop, sizeof(bool), cudaMemcpyHostToDevice);

        Kernel<<<grid, threads>>>(d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask, d_graph_visited, d_cost, no_of_nodes);
        cudaDeviceSynchronize();

        Kernel2<<<grid, threads>>>(d_graph_mask, d_updating_graph_mask, d_graph_visited, d_over, no_of_nodes);
        cudaDeviceSynchronize();

        cudaMemcpy(&stop, d_over, sizeof(bool), cudaMemcpyDeviceToHost);
        k++;
    }
    while(stop);

    cudaEventRecord(stop_event, 0);
    cudaEventSynchronize(stop_event);
    float elapsed_time;
    cudaEventElapsedTime(&elapsed_time, start_event, stop_event);
    printf("Compute time: %lf\n", elapsed_time / 1000.0);

    cudaMemcpy(h_cost, d_cost, sizeof(int)*no_of_nodes, cudaMemcpyDeviceToHost);

    FILE *fpo = fopen("result.txt", "w");
    for(int i = 0; i < no_of_nodes; i++)
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    fclose(fpo);
    printf("Result stored in result.txt\n");

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);

    cudaFree(d_graph_nodes);
    cudaFree(d_graph_edges);
    cudaFree(d_graph_mask);
    cudaFree(d_updating_graph_mask);
    cudaFree(d_graph_visited);
    cudaFree(d_cost);
    cudaFree(d_over);

    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);
}

int main(int argc, char** argv)
{
    BFSGraph(argc, argv);
}

